### Connection Pooling — Critical for Production

Every database connection is expensive (TCP handshake, auth, memory). Connection pools maintain a set of reusable connections.

```js
// pg (raw PostgreSQL) with pooling
const { Pool } = require('pg');

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  max: 20,                // max connections in pool
  min: 5,                 // keep min idle connections
  idleTimeoutMillis: 30000, // close idle connections after 30s
  connectionTimeoutMillis: 5000, // fail after 5s if no connection available
  ssl: process.env.NODE_ENV === 'production' ? { rejectUnauthorized: false } : false
});

// Always release connections back to pool
async function queryWithPool(sql, params) {
  const client = await pool.connect();
  try {
    const result = await client.query(sql, params);
    return result.rows;
  } finally {
    client.release();  // critical — always release
  }
}

// Graceful shutdown
process.on('SIGTERM', async () => {
  await pool.end();
  process.exit(0);
});
```

### Interview Insight

"What is the N+1 query problem and how does each ORM solve it?" — The N+1 problem occurs when you fetch N users then make 1 additional query per user to fetch their posts = N+1 total queries. Prisma solves it with `include` (generates a JOIN). Sequelize solves it with `include` in `findAll`. Mongoose solves it with `populate()`. All convert N+1 queries into 1-2 SQL queries.

## Session 6: File Handling and Streams

Node.js streams are one of its most powerful and most misunderstood features. Instead of loading an entire file into memory before processing, streams process data in chunks, allowing you to handle files larger than available RAM with constant memory usage.

### Buffers

A `Buffer` is a fixed-size allocation of raw memory outside the V8 heap, used to hold binary data.

```js
// Creating buffers
const buf1 = Buffer.alloc(10);                      // 10 bytes, zero-filled
const buf2 = Buffer.from('Hello, Node.js', 'utf8');  // from string
const buf3 = Buffer.from([0x48, 0x65, 0x6c, 0x6c, 0x6f]); // from bytes

console.log(buf2.toString('utf8'));   // 'Hello, Node.js'
console.log(buf2.toString('hex'));    // hex representation
console.log(buf2.toString('base64')); // base64 encoded

// Concatenate buffers (important: don't do this in a loop — O(n²))
const chunks = [];
// ... collect chunks ...
const combined = Buffer.concat(chunks); // O(n) — do once at the end
```

### Stream Types

- **Readable** — source of data (fs.createReadStream, http.IncomingMessage, process.stdin)
- **Writable** — destination for data (fs.createWriteStream, http.ServerResponse, process.stdout)
- **Duplex** — both readable and writable (net.Socket, TCP connections)
- **Transform** — duplex that transforms data as it passes through (zlib, crypto streams)

### Piping Streams — File Compression

```js
const fs = require('fs');
const zlib = require('zlib');
const { pipeline } = require('stream/promises');  // handles errors and cleanup

async function compressFile(inputPath, outputPath) {
  await pipeline(
    fs.createReadStream(inputPath),
    zlib.createGzip(),
    fs.createWriteStream(outputPath)
  );
  console.log(`Compressed ${inputPath} → ${outputPath}`);
}

async function decompressFile(inputPath, outputPath) {
  await pipeline(
    fs.createReadStream(inputPath),
    zlib.createGunzip(),
    fs.createWriteStream(outputPath)
  );
}

// Usage
compressFile('large-dataset.csv', 'large-dataset.csv.gz');
```

### Custom Transform Stream

```js
const { Transform } = require('stream');

// CSV line counter and parser
class CSVParser extends Transform {
  constructor() {
    super({ objectMode: true });  // output objects, not buffers
    this._buffer = '';
    this._headers = null;
    this._lineCount = 0;
  }

  _transform(chunk, encoding, callback) {
    this._buffer += chunk.toString();
    const lines = this._buffer.split('\n');
    this._buffer = lines.pop();  // keep incomplete last line

    for (const line of lines) {
      if (!this._headers) {
        this._headers = line.split(',').map(h => h.trim());
      } else if (line.trim()) {
        const values = line.split(',');
        const row = {};
        this._headers.forEach((h, i) => { row[h] = values[i]?.trim(); });
        this.push(row);  // emit object downstream
        this._lineCount++;
      }
    }
    callback();
  }

  _flush(callback) {
    if (this._buffer.trim() && this._headers) {
      const values = this._buffer.split(',');
      const row = {};
      this._headers.forEach((h, i) => { row[h] = values[i]?.trim(); });
      this.push(row);
    }
    console.log(`Parsed ${this._lineCount} rows`);
    callback();
  }
}

// Process a 1 GB CSV with constant memory usage
async function processLargeCSV(filePath) {
  const results = [];
  await pipeline(
    fs.createReadStream(filePath),
    new CSVParser(),
    new Transform({
      objectMode: true,
      transform(row, enc, cb) {
        // Filter and transform rows
        if (Number(row.price) > 100) {
          results.push(row);
        }
        cb();
      }
    })
  );
  return results;
}
```

### File Uploads with Multer

```js
const multer = require('multer');
const path = require('path');
const crypto = require('crypto');

// Disk storage with secure naming
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, path.join(__dirname, '../uploads'));
  },
  filename: (req, file, cb) => {
    const unique = crypto.randomBytes(16).toString('hex');
    const ext = path.extname(file.originalname).toLowerCase();
    cb(null, `${unique}${ext}`);
  }
});

const fileFilter = (req, file, cb) => {
  const allowed = ['image/jpeg', 'image/png', 'image/webp'];
  if (allowed.includes(file.mimetype)) {
    cb(null, true);
  } else {
    cb(new Error('Invalid file type. Only JPEG, PNG, WebP allowed.'), false);
  }
};

const upload = multer({
  storage,
  fileFilter,
  limits: { fileSize: 5 * 1024 * 1024, files: 5 }  // 5 MB per file, max 5 files
});

// Single file upload
router.post('/avatar', upload.single('avatar'), async (req, res, next) => {
  try {
    if (!req.file) return res.status(400).json({ error: 'No file uploaded' });
    await db.user.update({
      where: { id: req.user.id },
      data: { avatarPath: req.file.filename }
    });
    res.json({ path: `/uploads/${req.file.filename}` });
  } catch (err) { next(err); }
});

// Streaming file download
router.get('/files/:filename', async (req, res, next) => {
  try {
    const filePath = path.join(__dirname, '../uploads', req.params.filename);
    // Security: prevent path traversal
    if (!filePath.startsWith(path.join(__dirname, '../uploads'))) {
      return res.status(403).json({ error: 'Forbidden' });
    }
    const stat = await fs.promises.stat(filePath);
    res.setHeader('Content-Length', stat.size);
    res.setHeader('Content-Type', 'application/octet-stream');
    res.setHeader('Content-Disposition', `attachment; filename="${req.params.filename}"`);
    fs.createReadStream(filePath).pipe(res);
  } catch (err) {
    if (err.code === 'ENOENT') return res.status(404).json({ error: 'File not found' });
    next(err);
  }
});
```

### Interview Insight

"Why use streams instead of reading the whole file at once?" — `fs.readFile` loads the entire file into memory. A 2 GB file requires 2 GB of RAM. With a stream, Node.js reads in ~64 KB chunks, processes each chunk, and discards it — memory usage stays nearly constant regardless of file size. Streams also reduce time-to-first-byte: you can start sending the response before finishing reading the file.

## Session 7: WebSockets and Real-time Communication

HTTP's request-response model requires the client to poll for updates. Real-time features — chat, live notifications, collaborative editing, live dashboards — require the server to push data to clients. WebSockets and Server-Sent Events (SSE) are the two main approaches.

### WebSockets vs SSE vs Long Polling

| Feature | WebSockets | SSE | Long Polling |
|---------|-----------|-----|-------------|
| Direction | Bidirectional | Server → Client only | Server → Client |
| Protocol | WS/WSS | HTTP | HTTP |
| Connection | Persistent | Persistent | Reconnects per message |
| Browser support | Universal | Universal (not IE) | Universal |
| Proxy friendly | Sometimes | Yes | Yes |
| Use case | Chat, games, collaboration | Live feeds, notifications | Legacy fallback |

### Socket.io — Full-Featured WebSocket Library

```js
// server.js
const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const jwt = require('jsonwebtoken');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: { origin: process.env.CLIENT_URL, credentials: true },
  pingTimeout: 60000,
  pingInterval: 25000
});

// Authentication middleware for Socket.io
io.use((socket, next) => {
  const token = socket.handshake.auth.token;
  if (!token) return next(new Error('Authentication required'));
  try {
    const payload = jwt.verify(token, process.env.JWT_SECRET);
    socket.user = payload;  // attach user to socket
    next();
  } catch (err) {
    next(new Error('Invalid token'));
  }
});

// Namespace for chat
