chat.on('connection', async (socket) => {
  console.log(`User ${socket.user.email} connected`);

  // Join a room (e.g., a chat channel)
  socket.on('join:room', async (roomId) => {
    // Verify user has access to this room
    const hasAccess = await RoomService.userHasAccess(socket.user.id, roomId);
    if (!hasAccess) {
      socket.emit('error', { message: 'Access denied to room ' + roomId });
      return;
    }
    socket.join(roomId);
    socket.emit('room:joined', { roomId });
    // Notify others in the room
    socket.to(roomId).emit('user:joined', { userId: socket.user.id, email: socket.user.email });
  });

  // Handle chat message
  socket.on('message:send', async ({ roomId, content }) => {
    if (!content || content.length > 2000) {
      socket.emit('error', { message: 'Invalid message' });
      return;
    }
    const message = await MessageService.create({
      roomId, content, authorId: socket.user.id
    });
    // Broadcast to all in room including sender
    chat.to(roomId).emit('message:new', message);
  });

  // Handle typing indicator
  socket.on('typing:start', ({ roomId }) => {
    socket.to(roomId).emit('user:typing', { userId: socket.user.id });
  });

  socket.on('disconnect', () => {
    console.log(`User ${socket.user.email} disconnected`);
  });
});

server.listen(3000);
