### SQL Injection Prevention

```js
// VULNERABLE — never do this
app.get('/users', async (req, res) => {
  const { name } = req.query;
  // Injection: ?name='; DROP TABLE users; --
  const users = await db.query(`SELECT * FROM users WHERE name = '${name}'`);
  res.json(users);
});

// SAFE — parameterized queries
app.get('/users', async (req, res) => {
  const { name } = req.query;
  // pg library with parameterized query
  const { rows } = await pool.query(
    'SELECT id, name, email FROM users WHERE name = $1',
    [name]  // passed separately — never interpolated into SQL
  );
  res.json(rows);
});

// SAFE — Prisma (uses parameterized queries internally)
const users = await prisma.user.findMany({ where: { name: req.query.name } });

// SAFE — raw query with Prisma still uses parameterization
const results = await prisma.$queryRaw`
  SELECT id, name FROM users WHERE email = ${req.query.email}
`;
// Template literal with Prisma.$queryRaw is automatically parameterized
```

### XSS (Cross-Site Scripting) Prevention

```js
const DOMPurify = require('isomorphic-dompurify');

// If your API stores and serves user-generated HTML
router.post('/comments', async (req, res, next) => {
  try {
    const { content } = req.body;
    // Sanitize HTML before storing
    const sanitized = DOMPurify.sanitize(content, {
      ALLOWED_TAGS: ['b', 'i', 'u', 'em', 'strong', 'a', 'p'],
      ALLOWED_ATTR: ['href']
    });
    const comment = await db.comment.create({ data: { content: sanitized } });
    res.status(201).json(comment);
