### Input Sanitization and Prototype Pollution

```js
const hpp = require('hpp');  // HTTP Parameter Pollution protection

app.use(hpp());  // prevents: ?foo=bar&foo=baz (takes last value only)

// Prototype pollution prevention — never merge untrusted input into objects directly
// VULNERABLE
const config = {};
Object.assign(config, req.body);  // { __proto__: { admin: true } } pollutes Object.prototype

// SAFE — use validated schema output, not raw req.body
const safeConfig = createSchema.parse(req.body);  // zod strips unknown keys

// SAFE — Object.create(null) creates object with no prototype
const cleanConfig = Object.create(null);
